#include <bits/stdc++.h>
using namespace std;
int main()
{
    long long n,m;
    cin>>n>>m;
    long long zheng=0,chang=0;
    for(int i=0;i<n;i++)
    {
    	for(int j=0;j<m;j++)
    	{
    		if(i==j)
    		{
    			zheng=zheng+(n-i)*(m-j); 
			}
			else
			{
				chang=chang+(n-i)*(m-j);
			}
		}
	}
	cout<<zheng<<" "<<chang;
    return 0;
}
